# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
from boto3 import resource

def lambda_handler(event, context):
    db_resource = resource('rds')
    db_instance = db_resource.describe_db_instances()[0]
    
    if 'query' in event:
        query = event['query']
        
        # Remove leading and trailing whitespaces from query parameters
        query_params = {}
        for key, value in event.items():
            if key != 'query':
                param_key = key.strip()
                query_params[param_key] = str(value).strip()
                
        try:
            conn = pymysql.connect(host=db_instance['DBInstanceArn'].split(':')[5].split('-')[0],
                                   user='username', 
                                   password='password',
                                   database='database_name')
            
            cur = conn.cursor()
            
            where_clause = ''
            params = []
            
            for key, value in query_params.items():
                if where_clause:
                    where_clause += ' AND '
                where_clause += f'{key} = %s'
                params.append(value)
                
            sql_query = f"SELECT * FROM products WHERE {where_clause}"
            cur.execute(sql_query, tuple(params))
            
            results = cur.fetchall()
            conn.close()
            
            return {
                "statusCode": 200,
                "body": str(results)
            }
        
        except Exception as e:
            print(e)
            return {
                "statusCode": 500
            }
    
    else:
        return {
            "statusCode": 400
        }